prompt:
I'm curious, how many times will the variable i loop in the nested loop?
#include <iostream>
int main() {
int total = 0;
for (int i = 1; i <= 52; ++i) {
for (int j = 14; j <= i; ++j) {
if (i % 2 == 0) {
total += i * j;
} else {
total -= i * j;
}
}
}
std::cout << "Result: " << total << std::endl;

return 0;
}
